Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "autosize": {"type": "fit", "contains": "padding", "resize": true},
  "background": "transparent",
  "padding": {"top": 4, "left": 50, "right": 24, "bottom": 36},
  "data": [
    {
      "name": "dataset",
      "transform": [
        {
          "type": "filter",
          "expr": "datum[''RSI (14-Day)''] > 0 && datum[''RSI (14-Day)''] < 100 && datum.Volume < 2000000000"
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "xscale",
      "type": "linear",
      "domain": [0, 100],
      "range": "width",
      "zero": true
    },
    {
      "name": "yscale",
      "type": "sqrt",
      "domain": {"data": "dataset", "field": "Volume"},
      "range": "height",
      "nice": true,
      "zero": true
    }
  ],
  "axes": [
    {
      "orient": "bottom",
      "scale": "xscale",
      "title": "Relative Strength Index (RSI)",
      "titleColor": "#86868b",
      "titleFontWeight": "normal",
      "titlePadding": 8,
      "values": [0, 30, 50, 70, 100],
      "grid": false,
      "domain": false,
      "ticks": false,
      "labelColor": "#86868b",
      "labelFont": "system-ui, -apple-system, sans-serif",
      "labelFontSize": 11
    },
    {
      "orient": "left",
      "scale": "yscale",
      "title": "Daily Volume (Square Root Scale)",
      "titleColor": "#86868b",
      "titleFontWeight": "normal",
      "titlePadding": 8,
      "tickCount": 5,
      "format": "~s",
      "grid": true,
      "domain": false,
      "ticks": false,
      "gridColor": "#2a2a2d",
      "gridDash": [2, 4],
      "labelColor": "#86868b",
      "labelFont": "system-ui, -apple-system, sans-serif",
      "labelFontSize": 11
    }
  ],
  "marks": [
    {
      "type": "rule",
      "encode": {
        "enter": {
          "x": {"scale": "xscale", "value": 30},
          "y": {"value": 0},
          "y2": {"signal": "height"},
          "stroke": {"value": "#30d158"},
          "strokeDash": {"value": [4, 4]},
          "opacity": {"value": 0.6}
        }
      }
    },
    {
      "type": "rule",
      "encode": {
        "enter": {
          "x": {"scale": "xscale", "value": 70},
          "y": {"value": 0},
          "y2": {"signal": "height"},
          "stroke": {"value": "#ff453a"},
          "strokeDash": {"value": [4, 4]},
          "opacity": {"value": 0.6}
        }
      }
    },
    {
      "type": "symbol",
      "from": {"data": "dataset"},
      "encode": {
        "enter": {
          "x": {"scale": "xscale", "field": "RSI (14-Day)"},
          "y": {"scale": "yscale", "field": "Volume"},
          "size": {"value": 45},
          "fill": [
            {"test": "datum[''RSI (14-Day)''] <= 30", "value": "#30d158"},
            {"test": "datum[''RSI (14-Day)''] >= 70", "value": "#ff453a"},
            {"value": "#64d2ff"}
          ],
          "tooltip": {
            "signal": "{''Date'': timeFormat(datum.Trade_Date, ''%b %d, %Y''), ''RSI Level'': format(datum[''RSI (14-Day)''], ''.1f''), ''Volume'': format(datum.Volume, '','')}"
          }
        },
        "update": {
          "fillOpacity": {"value": 0.6},
          "size": {"value": 45}
        },
        "hover": {
          "fillOpacity": {"value": 1.0},
          "size": {"value": 100}
        }
      }
    }
  ]
}'
